Add a test for a multi-word query where terms match but phrase does not:
```ts
it('computes similarity without phraseBoost when query terms match but phrase is absent', async () => {
  mockGenerateEmbeddings.mockRejectedValue(new Error('AI unavailable'))
  mockNotesToArray.mockResolvedValue([
    makeNote({ id: 'note-1', content: 'React helps you understand side effects.' }),
  ])
  const result = await retrieveRelevantNotes('react effects')
  expect(result).toHaveLength(1)
  // 'react effects' as a phrase is NOT in the text, so no phraseBoost; 2/2 term ratio = 1.0
  expect(result[0].similarity).toBeCloseTo(1.0)
})
```

Add targeted tests:
```ts
it('matches fallback search against note tags', async () => {
  mockGenerateEmbeddings.mockRejectedValue(new Error('AI unavailable'))
  mockNotesToArray.mockResolvedValue([
    makeNote({ id: 'note-1', content: 'Unrelated prose.', tags: ['typescript', 'generics'] }),
  ])
  const result = await retrieveRelevantNotes('typescript')
  expect(result).toHaveLength(1)
  expect(result[0].note.id).toBe('note-1')
})

it('matches fallback search against courseId', async () => {
  mockGenerateEmbeddings.mockRejectedValue(new Error('AI unavailable'))
  mockNotesToArray.mockResolvedValue([
    makeNote({ id: 'note-1', content: 'Unrelated.', courseId: 'advanced-react' }),
  ])
  const result = await retrieveRelevantNotes('advanced react')
  expect(result.some(r => r.note.id === 'note-1')).toBe(true)
})
```

